import 'package:flutter/material.dart';

void main() => runApp(MyApp());

class MyApp extends StatelessWidget {
  @override
  Widget build(BuildContext context) {
    return MaterialApp(
      home: Scaffold(
        appBar: AppBar(title: Text('Widget示例')),
        body: Center(
          child: MyCounter(), // 使用StatefulWidget
        ),
      ),
    );
  }
}

// StatelessWidget示例：纯展示
class Greeting extends StatelessWidget {
  final String name;
  Greeting(this.name);

  @override
  Widget build(BuildContext context) {
    return Text('你好，$name！'); // 不会改变
  }
}

// StatefulWidget示例：计数器
class MyCounter extends StatefulWidget {
  @override
  _MyCounterState createState() => _MyCounterState();
}

class _MyCounterState extends State<MyCounter> {
  int _count = 0; // 状态变量

  void _increment() {
    setState(() {
      _count++; // 通知Flutter：状态已变，请重建
    });
  }

  @override
  Widget build(BuildContext context) {
    return Column(
      mainAxisAlignment: MainAxisAlignment.center,
      children: [
        Greeting('Flutter'), // 调用StatelessWidget
        Text('计数：$_count', style: TextStyle(fontSize: 24)),
        ElevatedButton(
          onPressed: _increment,
          child: Text('点击增加'),
        ),
      ],
    );
  }
}

